import{_ as a,o,c as l,a2 as r}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"富士康 / 苹果：工人权益与品牌压力（2010–至今）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/cases/csr/foxconn-apple.md","filePath":"zh/cases/csr/foxconn-apple.md"}'),i={name:"zh/cases/csr/foxconn-apple.md"};function e(n,t,s,d,h,u){return o(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="富士康-苹果-工人权益与品牌压力-2010–至今" tabindex="-1">富士康 / 苹果：工人权益与品牌压力（2010–至今） <a class="header-anchor" href="#富士康-苹果-工人权益与品牌压力-2010–至今" aria-label="Permalink to &quot;富士康 / 苹果：工人权益与品牌压力（2010–至今）&quot;">​</a></h1><p><strong>当&quot;最严审核&quot;遭遇&quot;最低成本&quot;</strong></p><blockquote><p><strong>关联指南：</strong> <a href="/zh/csr-guide.html">企业社会责任审核指南</a> · <strong>适用行业：</strong> 消费电子、代工制造</p></blockquote><hr><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>富士康科技集团（鸿海精密旗下）是全球最大的电子产品代工厂，iPhone、iPad、MacBook 等苹果核心产品均在其工厂组装。2010年，富士康深圳龙华工厂发生连续工人跳楼事件，引发全球关注，成为供应链劳工问题的标志性事件。</p><hr><h2 id="事件时间线" tabindex="-1">事件时间线 <a class="header-anchor" href="#事件时间线" aria-label="Permalink to &quot;事件时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>事件</th></tr></thead><tbody><tr><td>2010年1–11月</td><td>深圳龙华/观澜工厂发生<strong>18起工人坠楼事件</strong>，其中14人死亡</td></tr><tr><td>2010年5月</td><td>苹果委托公正劳工协会（FLA）开展审核，富士康提高基本工资30%</td></tr><tr><td>2012年3月</td><td>FLA 发布报告：确认存在<strong>过度加班、安全隐患、工资欠付</strong>等问题</td></tr><tr><td>2012年10月</td><td>郑州工厂爆发工人罢工，起因为质量检验员苛责导致的劳动争议</td></tr><tr><td>2014年</td><td>成都和郑州工厂被记录仍存在周工时超过60小时的情况</td></tr><tr><td>2019年</td><td>中国劳工通讯与澳大利亚战略政策研究所报告显示加班问题持续</td></tr><tr><td>2022年11月</td><td>郑州工厂（&quot;iPhone城&quot;）爆发大规模工人骚乱，起因为防疫封控与奖金纠纷</td></tr></tbody></table><hr><h2 id="审核局限性的典型案例" tabindex="-1">审核局限性的典型案例 <a class="header-anchor" href="#审核局限性的典型案例" aria-label="Permalink to &quot;审核局限性的典型案例&quot;">​</a></h2><p>苹果是业内对供应商审核投入最大的品牌之一——每年发布《供应商责任进展报告》，对数百家工厂进行审核。然而，问题为何持续？</p><h3 id="问题根源" tabindex="-1">问题根源 <a class="header-anchor" href="#问题根源" aria-label="Permalink to &quot;问题根源&quot;">​</a></h3><p><strong>1. 结构性矛盾未解决</strong></p><p>苹果的季节性订单峰谷落差极大（尤其是 iPhone 发布窗口），要求富士康在短时间内大幅扩充产能。这导致：</p><ul><li>工厂需要大量<strong>临时工/劳务派遣工</strong>（在中国，这类工人劳动保护较弱）</li><li>旺季加班时长系统性超标，即便工人&quot;自愿&quot;，也受到隐性压力</li></ul><p><strong>2. 审核时机与频率</strong></p><ul><li>审核通常提前安排，工厂有时间&quot;整理&quot;出勤记录</li><li>旺季（需求最大、违规最多时）反而是审核空窗期</li><li>FLA 2012年报告显示：<strong>超过50%的受访工人表示曾加班超过法定上限</strong>，而工厂仍通过了苹果的审核</li></ul><p><strong>3. 工人声音渠道失效</strong></p><ul><li>工厂内部设有投诉热线，但工人普遍不信任匿名性</li><li>独立工会在中国受到法律限制</li><li>研究发现，工人在接受审核员访谈时，有时被管理层提前&quot;辅导&quot;</li></ul><p><strong>4. 自杀事件的深层原因</strong></p><p>2010年事件后，富士康在宿舍楼加装防坠网，被媒体称为&quot;自杀防护网&quot;——这一应急措施本身说明问题在于<strong>系统性压力</strong>（高强度流水线、宿舍式管理、与家乡的社会隔绝），而非个案心理问题。</p><hr><h2 id="企业与行业的回应" tabindex="-1">企业与行业的回应 <a class="header-anchor" href="#企业与行业的回应" aria-label="Permalink to &quot;企业与行业的回应&quot;">​</a></h2><h3 id="苹果的措施" tabindex="-1">苹果的措施 <a class="header-anchor" href="#苹果的措施" aria-label="Permalink to &quot;苹果的措施&quot;">​</a></h3><ul><li>加入 FLA（公正劳工协会），接受第三方监督</li><li>发布年度《供应商责任进展报告》（2007年至今）</li><li>要求富士康将月基本工资提升至不低于当地最低工资的1.5倍</li><li>推出<strong>供应商员工教育计划</strong>（免费大学课程、职业培训）</li><li>2022年承诺在供应链中推广**&quot;负责任招募&quot;**，消除招募费（以减少债务束缚）</li></ul><h3 id="富士康的措施" tabindex="-1">富士康的措施 <a class="header-anchor" href="#富士康的措施" aria-label="Permalink to &quot;富士康的措施&quot;">​</a></h3><ul><li>多次上调基本工资（2010、2012、2018年均有调薪）</li><li>引入机器人生产线（部分替代重复性流水线岗位）</li><li>加强工人援助计划（EAP）与心理辅导</li><li>在郑州、成都等内陆城市建设新厂，使工人离家更近</li></ul><hr><h2 id="对审核实践的启示" tabindex="-1">对审核实践的启示 <a class="header-anchor" href="#对审核实践的启示" aria-label="Permalink to &quot;对审核实践的启示&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">关键审核问题</p><p><strong>在电子代工供应商的工人访谈中，务必询问：</strong></p><ol><li>您本月实际工作了多少小时？旺季呢？（与工资单交叉核验）</li><li>您是正式员工还是劳务派遣/临时工？派遣比例是否超过10%（中国法规上限）？</li><li>如果您因健康或个人原因拒绝加班，会有什么后果？</li><li>宿舍/食堂费用是从工资中扣除的吗？扣除额是否合理透明？</li><li>您知道厂内有投诉渠道吗？您会使用它吗？为什么？</li></ol><p><strong>文件审核重点：</strong></p><ul><li>比对旺季（Q3-Q4）与淡季的出勤记录，识别系统性超时规律</li><li>核查劳务派遣合同比例（中国《劳务派遣暂行规定》上限10%）</li><li>要求工资单原件，核算隐性费用（餐费、住宿费、工装费扣除后的实得工资）</li></ul></div><hr><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>Fair Labor Association: <em>Foxconn Verification Status Reports</em> (2012–2014)</li><li>Apple: <em>Supplier Responsibility Progress Report</em> (年度)</li><li>China Labor Watch: <em>Apple&#39;s Broken Promises</em> (2014)</li><li>Jenny Chan, Mark Selden, Ngai Pun: <em>Dying for an iPhone</em> (2020)</li><li>The New York Times: <em>In China, Human Costs Are Built Into an iPad</em> (2012)</li></ul>',34)])])}const q=a(i,[["render",e]]);export{p as __pageData,q as default};
